import React, { useState, useEffect } from 'react';
import { Users, Map as MapIcon, ThumbsUp, ThumbsDown, UserPlus, Plus, MapPin } from 'lucide-react';
import { supabase } from '../../services/supabaseClient';

function ConvoyView() {
  const [proposals, setProposals] = useState([]);
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newPlaceName, setNewPlaceName] = useState('');

  const fetchProposals = async () => {
    const { data, error } = await supabase
      .from('proposals')
      .select('*')
      .order('id', { ascending: true });

    if (!error) {
      setProposals(data);
    }
  };

  // NYTT: Nu lyssnar vi i realtid!
  useEffect(() => {
    // 1. Hämta listan första gången appen startar
    fetchProposals();

    // 2. Sätt upp radiomottagaren (lyssnar på vår tabell)
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'proposals' },
        (payload) => {
          console.log('Databasen uppdaterades! Laddar om listan...', payload);
          // Någon (eller du) ändrade något! Vi hämtar den senaste listan direkt.
          fetchProposals();
        }
      )
      .subscribe();

    // Stäng av mottagaren om vi byter flik i appen (sparar batteri)
    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  const handleVote = async (id, type) => {
    const proposal = proposals.find(p => p.id === id);
    if (!proposal) return;

    const isUpvote = type === 'up';
    const newVotesUp = isUpvote ? proposal.votes_up + 1 : proposal.votes_up;
    const newVotesDown = !isUpvote ? proposal.votes_down + 1 : proposal.votes_down;

    // Vi uppdaterar lokalt direkt för snabbhetens skull...
    setProposals(proposals.map(p => 
      p.id === id ? { ...p, votes_up: newVotesUp, votes_down: newVotesDown } : p
    ));

    // ...och skickar upp det till molnet (vilket kommer trigga realtiden för ALLA ANDRA)
    await supabase
      .from('proposals')
      .update({ votes_up: newVotesUp, votes_down: newVotesDown })
      .eq('id', id);
  };

  const handleAddProposal = async () => {
    if (newPlaceName.trim() === '') return;

    const fakeWeather = ['☀️ 22°C', '⛅ 19°C', '🌧️ 14°C'][Math.floor(Math.random() * 3)];

    const { error } = await supabase
      .from('proposals')
      .insert([{ name: newPlaceName, weather: fakeWeather, votes_up: 0, votes_down: 0 }]);

    if (!error) {
      setShowAddModal(false);
      setNewPlaceName('');
      // Vi behöver inte ens lägga till den i listan manuellt längre,
      // eftersom vår Realtids-lyssnare kommer upptäcka det och göra det åt oss!
    } else {
      alert("Kunde inte spara platsen: " + error.message);
    }
  };

  return (
    <div style={{ padding: '20px' }} className="animate-fade-in">

      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27', margin: 0, display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Users size={28} /> Min Konvoj
        </h1>
        <button 
          onClick={() => setShowInviteModal(true)}
          style={{ backgroundColor: '#E8F5E9', padding: '8px 15px', borderRadius: '20px', color: '#2D5A27', fontSize: '14px', fontWeight: 'bold', border: 'none', cursor: 'pointer', boxShadow: '0 2px 5px rgba(0,0,0,0.05)', display: 'flex', alignItems: 'center', gap: '6px' }}>
          <UserPlus size={16} /> Bjud in
        </button>
      </header>

      <div style={{ backgroundColor: '#DCEBDE', height: '180px', borderRadius: '20px', display: 'flex', justifyContent: 'center', alignItems: 'center', marginBottom: '20px', boxShadow: 'inset 0 2px 10px rgba(0,0,0,0.05)' }}>
        <div style={{ textAlign: 'center', color: '#2D5A27', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
          <MapIcon size={36} style={{ marginBottom: '10px', opacity: 0.8 }} />
          <span style={{ fontWeight: 'bold' }}>Live-karta kommer här</span>
        </div>
      </div>

      <h2 style={{ fontSize: '18px', marginBottom: '15px' }}>Omröstning: Nattplats</h2>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>

        {proposals.length === 0 && (
          <p style={{ color: '#636E72', textAlign: 'center', fontStyle: 'italic' }}>Laddar nattplatser från molnet...</p>
        )}

        {proposals.map((prop) => (
          <div key={prop.id} style={{ backgroundColor: '#FFF', padding: '15px', borderRadius: '15px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
              <span style={{ fontWeight: 'bold', fontSize: '16px' }}>{prop.name}</span>
              <span style={{ fontSize: '14px', backgroundColor: '#F5F2ED', padding: '4px 8px', borderRadius: '10px' }}>{prop.weather}</span>
            </div>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => handleVote(prop.id, 'up')} style={voteBtnStyle(true)}>
                <ThumbsUp size={18} /> {prop.votes_up}
              </button>
              <button onClick={() => handleVote(prop.id, 'down')} style={voteBtnStyle(false)}>
                <ThumbsDown size={18} /> {prop.votes_down}
              </button>
            </div>
          </div>
        ))}
      </div>

      <button onClick={() => setShowAddModal(true)} style={primaryBtnStyle}>
        <Plus size={20} /> Lägg till ett förslag
      </button>

      {showAddModal && (
        <div style={overlayStyle} className="animate-fade-in">
          <div style={modalStyle}>
            <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '15px' }}>
              <div style={{ backgroundColor: '#E8F5E9', padding: '15px', borderRadius: '50%' }}>
                <MapPin size={32} color="#2D5A27" />
              </div>
            </div>
            <h2 style={{ marginTop: 0, color: '#2D5A27', textAlign: 'center', marginBottom: '20px' }}>Nytt förslag</h2>

            <input 
              type="text" 
              placeholder="T.ex. Skärgården Fricamping" 
              value={newPlaceName}
              onChange={(e) => setNewPlaceName(e.target.value)}
              style={{ width: '100%', padding: '15px', borderRadius: '10px', border: '2px solid #DCEBDE', fontSize: '16px', marginBottom: '20px', boxSizing: 'border-box', outline: 'none' }}
              autoFocus
            />

            <button onClick={handleAddProposal} style={{...primaryBtnStyle, marginTop: '0'}}>Spara förslag</button>
            <button onClick={() => setShowAddModal(false)} style={cancelBtnStyle}>Avbryt</button>
          </div>
        </div>
      )}

      {showInviteModal && (
        <div style={overlayStyle} className="animate-fade-in">
          <div style={modalStyle}>
            <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '20px' }}>
              <div style={{ backgroundColor: '#F5F2ED', padding: '20px', borderRadius: '50%' }}>
                <UserPlus size={40} color="#D35400" />
              </div>
            </div>
            <h2 style={{ marginTop: 0, color: '#2D5A27', textAlign: 'center' }}>Bjud in resekamrater</h2>
            <p style={{ color: '#636E72', lineHeight: '1.5', textAlign: 'center', marginBottom: '20px' }}>
              Dela denna unika kod med dina vänner så att de kan ansluta till din konvoj:
            </p>
            <div style={{ backgroundColor: '#F5F2ED', padding: '20px', borderRadius: '15px', textAlign: 'center', fontSize: '28px', fontWeight: 'bold', letterSpacing: '4px', margin: '20px 0', color: '#D35400', border: '2px dashed #DCEBDE' }}>
              CAMP-84X
            </div>
            <button onClick={() => setShowInviteModal(false)} style={cancelBtnStyle}>Stäng</button>
          </div>
        </div>
      )}

    </div>
  );
}

// --- DESIGNMALLAR ---
const primaryBtnStyle = { backgroundColor: '#2D5A27', color: 'white', border: 'none', padding: '16px', borderRadius: '15px', fontSize: '16px', fontWeight: 'bold', cursor: 'pointer', width: '100%', marginTop: '20px', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px' };
const voteBtnStyle = (isUpvote) => ({ flex: 1, padding: '10px', border: 'none', borderRadius: '10px', backgroundColor: isUpvote ? '#E8F5E9' : '#FFEBEE', color: isUpvote ? '#2D5A27' : '#C62828', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '6px' });
const overlayStyle = { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1100 };
const modalStyle = { backgroundColor: '#FFF', padding: '30px', borderRadius: '25px', width: '85%', maxWidth: '350px', boxShadow: '0 10px 40px rgba(0,0,0,0.2)' };
const cancelBtnStyle = { width: '100%', padding: '15px 0 0 0', backgroundColor: 'transparent', border: 'none', color: '#95A5A6', fontWeight: 'bold', cursor: 'pointer', fontSize: '14px', marginTop: '10px' };

export default ConvoyView;
